const input = $input.first().json;
const payload = input.payload || input.body || input;

// Cal.com sends attendees as an array
const attendee = payload?.attendees?.[0] || {};
const organizer = payload?.organizer || {};

const firstName = attendee.name?.split(' ')[0] || attendee.firstName || '';
const lastName = attendee.name?.split(' ').slice(1).join(' ') || attendee.lastName || '';
const email = attendee.email || '';
const timezone = attendee.timeZone || 'US/Eastern';
const eventTitle = payload.title || payload.type || 'Discovery Call';
const startTime = payload.startTime || '';
const endTime = payload.endTime || '';
const meetingUrl = payload.metadata?.videoCallUrl || payload.videoCallUrl || '';
const bookingUid = payload.uid || '';

// Format date nicely
let formattedDate = '';
try {
  const d = new Date(startTime);
  formattedDate = d.toLocaleDateString('en-US', { 
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    hour: '2-digit', minute: '2-digit', timeZone: timezone
  });
} catch(e) {
  formattedDate = startTime;
}

return [{
  json: {
    firstName,
    lastName,
    fullName: `${firstName} ${lastName}`.trim(),
    email,
    timezone,
    eventTitle,
    startTime,
    formattedDate,
    meetingUrl,
    bookingUid
  }
}];

