const booking = $('📋 Parse Booking Data').first().json;
const formData = $('🔍 Check Form Submitted').first().json;
const aiResponse = $input.first().json;

// Extract the brief text from OpenAI response
const briefText = aiResponse?.message?.content 
  || aiResponse?.text 
  || aiResponse?.choices?.[0]?.message?.content
  || 'Brief generation failed — please generate manually.';

const docTitle = `${booking.fullName} — Pre-Call Diagnostic Brief — ${new Date().toLocaleDateString('en-US')}`;

return [{
  json: {
    ...booking,
    briefText,
    docTitle,
    formSubmitted: !!formData.email,
    formData
  }
}];

